INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('84c70509-9e0c-5b5d-82d7-26a2e545cc8a', 'eveil-scientifique-5eme', 'التنفّس والجهاز التنفّسي', 'أعضاء الجهاز التنفّسي (الأنف، الرغامى، الرئتان)، حركتا الشهيق والزفير، وتبادل الأكسجين وغاز الفحم أثناء التنفّس', '# ⚔️ التنفّس والجهاز التنفّسي — نَفَسُ الحياة

> 💡 «نستطيع أن نصبر عن الأكل والشرب ساعاتٍ، لكنّنا لا نصبر عن التنفّس إلّا دقائق؛ فالتنفّس نَفَسُ الحياة.»

في كلّ لحظةٍ نأخذ هواءً ونطرده دون أن ننتبه. هذه العمليّة اسمها **التنفّس**، ويقوم بها **الجهاز التنفّسي**.

## 🌬️ ما هو التنفّس؟

**التنفّس** هو دخول الهواء إلى الجسم وخروجه منه باستمرار. يأخذ الجسم من الهواء غازًا مفيدًا اسمه **الأكسجين**، ويطرد غازًا غير مفيد اسمه **غاز الفحم** (ثاني أكسيد الكربون).

## 🫁 أعضاء الجهاز التنفّسي ومسار الهواء

يمرّ الهواء في طريقه إلى داخل الجسم عبر:

- **الأنف:** يدخل منه الهواء فيُصفّى ويُدفّأ.
- **الرغامى (القصبة الهوائيّة):** أنبوبٌ ينقل الهواء من الأنف إلى الرئتين.
- **الرئتان:** عضوان إسفنجيّان في الصدر، فيهما يأخذ الجسم الأكسجين ويطرح غاز الفحم.

> 🧭 مسار الهواء عند الدخول: الأنف ← الرغامى ← الرئتان.

## 🔄 حركتا الشهيق والزفير

يتنفّس الجسم بحركتين متعاقبتين:

- **الشهيق:** ندخل الهواء إلى الرئتين، فينتفخ الصدر (هواء غنيّ بالأكسجين).
- **الزفير:** نُخرج الهواء من الرئتين، فينكمش الصدر (هواء غنيّ بغاز الفحم).

> 🧪 جرّب: ضع يدك على صدرك؛ تشعر أنّه ينتفخ مع الشهيق وينكمش مع الزفير.

## 💨 الأكسجين وغاز الفحم

- **الهواء الذي ندخله (شهيق):** غنيّ بـ**الأكسجين** المفيد للجسم.
- **الهواء الذي نُخرجه (زفير):** غنيّ بـ**غاز الفحم** الذي طرحه الجسم.

ففي الرئتين يحدث **تبادل**: يأخذ الدم الأكسجين لينقله إلى الجسم، ويتخلّص من غاز الفحم.

## 🛡️ كيف نحافظ على جهازنا التنفّسي؟

- نتنفّس **هواءً نقيًّا** ونبتعد عن الدخان.
- نمارس **الرياضة** فتقوى الرئتان.
- نتجنّب الأماكن الملوّثة بالغبار والغازات.

> ⚠️ الفخّ الشائع: الظنّ أنّ الهواء الذي نُخرجه (الزفير) هو نفسه الذي ندخله؛ في الحقيقة هواء الزفير فقد كثيرًا من الأكسجين وامتلأ بغاز الفحم.

> 🏆 الآن صرت تعرف كيف يحصل جسمك على الأكسجين في كلّ نَفَس، ولماذا يجب أن نتنفّس هواءً نقيًّا.', '# 📜 ملخّص: التنفّس والجهاز التنفّسي

- **التنفّس:** دخول الهواء إلى الجسم وخروجه باستمرار؛ يأخذ الجسم الأكسجين ويطرد غاز الفحم.
- **أعضاء الجهاز التنفّسي:** الأنف، الرغامى (القصبة الهوائيّة)، الرئتان.
- **مسار الهواء عند الدخول:** الأنف ← الرغامى ← الرئتان.
- **الشهيق:** دخول الهواء إلى الرئتين فينتفخ الصدر (هواء غنيّ بالأكسجين).
- **الزفير:** خروج الهواء من الرئتين فينكمش الصدر (هواء غنيّ بغاز الفحم).
- **التبادل في الرئتين:** الدم يأخذ الأكسجين ويتخلّص من غاز الفحم.
- **المحافظة:** تنفّس هواءٍ نقيّ، الابتعاد عن الدخان، ممارسة الرياضة.', 2)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('1a51d111-7b2f-57c0-92c6-17be196d1d26', 'eveil-scientifique-5eme', 'الدورة الدمويّة', 'أعضاء الجهاز الدمويّ (القلب، الدم، الأوعية الدمويّة)، دور القلب كمضخّة، ودور الدم في نقل الأكسجين والغذاء إلى أعضاء الجسم', '# ⚔️ الدورة الدمويّة — نهرُ الحياة داخل الجسم

> 💡 «في جسمك نهرٌ أحمر لا يتوقّف؛ يجري ليلًا ونهارًا ليحمل الحياة إلى كلّ خليّة.»

في كلّ لحظةٍ يجري **الدم** في جسمك دون توقّف، يدفعه **القلب** عبر أنابيب دقيقة. هذه الرحلة المستمرّة اسمها **الدورة الدمويّة**.

## ❤️ أعضاء الجهاز الدمويّ

يتكوّن الجهاز الدمويّ من ثلاثة عناصر:

- **القلب:** عضوٌ عضليّ بحجم قبضة اليد، في الصدر؛ يعمل كـ**مضخّة** تدفع الدم.
- **الدم:** سائلٌ أحمر يجري في الجسم.
- **الأوعية الدمويّة:** أنابيب يجري فيها الدم (الشرايين والأوردة).

## 🫀 القلب: المضخّة التي لا تتعب

**القلب** عضلةٌ تنقبض وتنبسط باستمرار. مع كلّ **نبضة** يدفع الدم في الأوعية إلى كلّ الجسم. لا يتوقّف القلب لا في النوم ولا في اليقظة.

> 🧪 جرّب: ضع أصابعك على معصمك؛ تشعر بـ**النبض**، وهو أثر دفع القلب للدم.

## 🩸 دور الدم: ناقل الحياة

الدم لا يجري عبثًا؛ فهو **ينقل** أشياء مهمّة لكلّ أعضاء الجسم:

- ينقل **الأكسجين** من الرئتين إلى كلّ الأعضاء.
- ينقل **الغذاء المهضوم** من الأمعاء إلى كلّ الأعضاء.
- يحمل **الفضلات** وغاز الفحم ليتخلّص منها الجسم.

> 🧭 الدم همزة وصلٍ بين الأجهزة: يأخذ الأكسجين من الجهاز التنفّسي والغذاء من الجهاز الهضمي ويوزّعهما على الجسم.

## 🔁 رحلةٌ لا تنتهي

يخرج الدم من القلب محمّلًا بالأكسجين والغذاء، يوزّعهما على الأعضاء، ثمّ يعود إلى القلب ليُدفع من جديد. وهكذا تدور الدورة الدمويّة باستمرار.

## 🛡️ كيف نحافظ على قلبٍ سليم؟

- نمارس **الرياضة** فتقوى عضلة القلب.
- نتغذّى **غذاءً متوازنًا** ونُقلّل الدهون.
- نبتعد عن **الدخان** الذي يضرّ القلب والأوعية.

> ⚠️ الفخّ الشائع: الظنّ أنّ الدم يصنع الأكسجين والغذاء؛ في الحقيقة الدم **ينقلهما** فقط: الأكسجين من الرئتين، والغذاء من الأمعاء.

> 🏆 الآن صرت تعرف لماذا لا يتوقّف قلبك، وكيف يحمل دمك الحياة إلى كلّ خليّة في جسمك.', '# 📜 ملخّص: الدورة الدمويّة

- **الجهاز الدمويّ:** القلب + الدم + الأوعية الدمويّة (الشرايين والأوردة).
- **القلب:** عضلةٌ بحجم قبضة اليد تعمل كمضخّة تدفع الدم بنبضاتٍ لا تتوقّف.
- **النبض:** أثر دفع القلب للدم، نشعر به في المعصم.
- **دور الدم:** ينقل الأكسجين من الرئتين، والغذاء المهضوم من الأمعاء، إلى كلّ الأعضاء؛ ويحمل الفضلات وغاز الفحم.
- **الدم همزة وصل:** بين الجهاز التنفّسي والهضمي وبقيّة أعضاء الجسم.
- **الدورة الدمويّة:** يخرج الدم من القلب ويوزّع حمولته ثمّ يعود إليه باستمرار.
- **المحافظة:** ممارسة الرياضة، غذاء متوازن، الابتعاد عن الدخان.', 3)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
