INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3fb3b041-0e9e-5664-bd79-0023e5b98406', '94089f35-96c0-5649-a3cb-2be5fd7f4a3f', 'ما هو الترتيب الصحيح لمسار الغذاء؟', '[{"id":"a","text":"المعدة ← الفم ← المريء ← الأمعاء"},{"id":"b","text":"المريء ← الفم ← الأمعاء ← المعدة"},{"id":"c","text":"الفم ← المريء ← المعدة ← الأمعاء"},{"id":"d","text":"الأمعاء ← المعدة ← المريء ← الفم"}]'::jsonb, 'c', 'يمرّ الغذاء بالترتيب: الفم ثمّ المريء ثمّ المعدة ثمّ الأمعاء الدقيقة فالغليظة.', 3)
