INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9384743c-eea6-55c9-8097-8f7ad36ebcd4', 'f1f614b0-c4f2-589f-b052-82cce90254fa', 'شخصٌ يبتلع طعامه بسرعة دون مضغ. ما المشكل المتوقّع؟', '[{"id":"a","text":"يصعب هضم الطعام لأنّه لم يُطحن جيّدًا"},{"id":"b","text":"يهضم الطعام أسرع وأفضل"},{"id":"c","text":"لا يتأثّر الهضم إطلاقًا"},{"id":"d","text":"يتحوّل الطعام إلى دم فورًا"}]'::jsonb, 'a', 'المضغ يطحن الطعام ويخلطه باللعاب؛ بلعه بسرعة دون مضغ يجعل هضمه أصعب.', 1)
