INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83fc7a70-e9b4-58eb-bf64-61d8e1bef988', 'f1f614b0-c4f2-589f-b052-82cce90254fa', 'لماذا نقول إنّ الجهاز الهضمي يعمل كسلسلةٍ مترابطة؟', '[{"id":"a","text":"لأنّ كلّ عضوٍ يعمل وحده ولا علاقة له بغيره"},{"id":"b","text":"لأنّ كلّ عضوٍ يهيّئ الغذاء للعضو الذي يليه حتّى يكتمل الهضم"},{"id":"c","text":"لأنّ الأعضاء تعمل بالعكس"},{"id":"d","text":"لأنّ عضوًا واحدًا يقوم بكلّ شيء"}]'::jsonb, 'b', 'كلّ عضوٍ يهيّئ الغذاء للعضو الذي يليه: الفم يطحن، المريء يدفع، المعدة تخلط، والأمعاء تمتصّ.', 2)
